//---------------------------------------------------------
// Parameter Setting
// 다른 화면에서 들어올때 각 화면별 조건을 받아서 조회한다.
//---------------------------------------------------------
scwin.f_getParametrSetting = function (gubun) {
  gubun = Number(gubun);
  switch (gubun) {
    case 0:
      break;
    case 1:
      //Booking의 search Grid
      if (scwin.v_mhno == "null") {
        cnd_ed_mhno.setValue("");
        cnd_ed_mhno.focus();
        return false;
      }
      scwin.hd_kcomcd = scwin.v_kcomcd;
      cnd_ed_mhno.setValue(scwin.v_mhno);
      scwin.f_Retrieve();
      break;
    case 2:
      //House Search에서 던짐.
      if (scwin.v_mhno == "null") {
        cnd_ed_mhno.setValue("");
        cnd_ed_mhno.focus();
        return false;
      }
      scwin.hd_kcomcd = scwin.v_kcomcd;
      cnd_ed_mhno.setValue(scwin.v_mhno);
      scwin.f_Retrieve();
      break;
    case 4:
      // Booking 에서 h b/l버튼 (create)
      scwin.f_Create();
      scwin.hd_hhbkgno = "";
      scwin.f_BookingLoading();
      tab_main.setSelectedTabIndex(0); // 1번째 탭으로 이동.  cnd_ed_hhblno.focus() 잡아주기 위함.
      ed_mhlinercd.focus();
      break;
  }
};

