scwin.f_HouseLoading = async function () {
  var code = ds_bkseq.getCellData(ds_bkseq.getRowPosition() ?? 0, "code");
  if (code != "" && code != "undefiend") {
    dma_gridBulkList.undo();
    dma_gridBulkList.set("kcomcd", scwin.hd_kcomcd);
    dma_gridBulkList.set("hhbkgno", ds_houseblList.getCellData(ds_houseblList.getRowPosition() || 0, "hhbkgno"));
    dma_gridBulkList.set("hhbkgseq", ds_houseblList.getCellData(ds_houseblList.getRowPosition() || 0, "hhbkgseq"));
    await $c.sbm.execute($p, sbm_retrieveGridBulk);
  }
  if (ds_gridBulkList.getRowCount() == 0) {
    return;
  }
  ds_houseblList.setCellData(ds_houseblList.getRowPosition() || 0, "hhactcust", ds_gridBulkList.getCellData(ds_gridBulkList.getRowPosition() || 0, "hhactcust"));
  ds_houseblList.setCellData(ds_houseblList.getRowPosition() || 0, "hhactcustnm", ds_gridBulkList.getCellData(ds_gridBulkList.getRowPosition() || 0, "hhactcustnm"));
  ds_houseblList.setCellData(ds_houseblList.getRowPosition() || 0, "hhfaccd", ds_gridBulkList.getCellData(ds_gridBulkList.getRowPosition() || 0, "hhfaccd"));
  ds_houseblList.setCellData(ds_houseblList.getRowPosition() || 0, "hhfacnm", ds_gridBulkList.getCellData(ds_gridBulkList.getRowPosition() || 0, "hhfacnm"));
  if (ds_gridBulkList.getCellData(ds_gridBulkList.getRowPosition() || 0, "hhitem") != "") {
    ds_houseblList.setCellData(ds_houseblList.getRowPosition() || 0, "hhitem", ds_gridBulkList.getCellData(ds_gridBulkList.getRowPosition() || 0, "hhitem"));
    ds_houseblList.setCellData(ds_houseblList.getRowPosition() || 0, "hhmitem1", ds_gridBulkList.getCellData(ds_gridBulkList.getRowPosition() || 0, "hhmitem1"));
  }
  ds_houseblList.setCellData(ds_houseblList.getRowPosition() || 0, "hhscd", ds_gridBulkList.getCellData(ds_gridBulkList.getRowPosition() || 0, "hhscd"));
  ds_houseblList.setCellData(ds_houseblList.getRowPosition() || 0, "hhs1", ds_gridBulkList.getCellData(ds_gridBulkList.getRowPosition() || 0, "hhs1"));
  ds_houseblList.setCellData(ds_houseblList.getRowPosition() || 0, "hhnwgt", ds_gridBulkList.getCellData(ds_gridBulkList.getRowPosition() || 0, "hhnwgt"));
  ds_houseblList.setCellData(ds_houseblList.getRowPosition() || 0, "hhgwgt", ds_gridBulkList.getCellData(ds_gridBulkList.getRowPosition() || 0, "hhgwgt"));
  ds_houseblList.setCellData(ds_houseblList.getRowPosition() || 0, "hhpkg", ds_gridBulkList.getCellData(ds_gridBulkList.getRowPosition() || 0, "hhpkg"));
  ds_houseblList.setCellData(ds_houseblList.getRowPosition() || 0, "hhmsr", ds_gridBulkList.getCellData(ds_gridBulkList.getRowPosition() || 0, "hhmsr"));
  ds_gridBulkList.removeAll();
};

