scwin.f_departmentChange = async function () {
  if ($c.util.isEmpty($p, ed_mhbuyer.getValue())) {
    return;
  }
  let opts = {
    id: "ilCommonDeptChange",
    popupName: "Department Change",
    modal: true,
    type: "browserPopup",
    width: 460,
    height: 280,
    title: "부서"
  };
  const rtnList = await $c.win.openPopup($p, "/ui/il/common/xml/ilCommonDeptChange.xml", opts, {
    pdept: ed_mhbuyer.getValue(),
    pdeptnm: txt_mhbuyernm.getValue()
  });
  if (!rtnList || rtnList.length < 3) return;
  if (rtnList[0] !== "N/A") return;
  if ($c.util.isEmpty($p, String(rtnList[1]).trim()) || $c.util.isEmpty($p, String(rtnList[2]).trim())) return;
  if (!(await $c.win.confirm($p, E_MSG_CM_CRM_001))) return; // 저장하시겠습니까?

  // 파라미터 DS 세팅

  let modrNo = ds_bulkblList.getCellData(ds_bulkblList.getRowPosition() ?? 0, "odrNo");
  let dept = String(rtnList[1]).trim();
  let deptnm = String(rtnList[2]).trim();
  for (var i = 0; i < ds_houseblList.getRowCount(); i++) {
    dma_DeptChangeParam.set("modrNo", modrNo); // Order No
    dma_DeptChangeParam.set("hodrNo", ds_houseblList.getCellData(i, "odrNo"));
    dma_DeptChangeParam.set("kcomcd", scwin.hd_kcomcd); // 법인코드
    dma_DeptChangeParam.set("bulkGb", "B");
    dma_DeptChangeParam.set("dept", dept); // 변경할 부서 코드 
    dma_DeptChangeParam.set("deptnm", deptnm); // 변경할 부서  명

    // submit 실행 (sbm_DeptChange 기준)
    await $c.sbm.execute($p, sbm_DeptChange);
    const spRtn = ds_DeptChangeResult.getCellData(0, "spRtn");
    // const spMsg = ds_DeptChangeResult.getCellData(0, "spMsg");

    if (spRtn == "0") {
      //변경 성공 
      txt_mhbuyernm.setValue(String(rtnList[2]).trim());
      ed_mhbuyer.setValue(String(rtnList[1]).trim());
      await $c.win.alert($p, "House No:" + ds.getCellData(ds.getRowPosition(), "hodrNo") + "->Department 가 변경 되었습니다.");
    } else {
      // 필요하면 spMsg 표시
      await $c.win.alert($p, "House No:" + ds.getCellData(ds.getRowPosition(), "hodrNo") + "->이미 전표가 발행  되어 변경 불가능 합니다.");
    }
  }
};

